import { MakeLogicType, kea, path, selectors } from 'kea'

import { FEATURE_FLAGS } from 'lib/constants'
import { featureFlagLogic } from 'lib/logic/featureFlagLogic'
import { organizationLogic } from 'scenes/organizationLogic'


// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface interProjectCopyLogicValues {
    canCopyToProject: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface interProjectCopyLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        canCopyToProject: (currentOrganization: null | import("../../types").OrganizationType, featureFlags: import("lib/logic/featureFlagLogic").FeatureFlagsSet) => boolean;
    };
}

export type interProjectCopyLogicType = MakeLogicType<interProjectCopyLogicValues, {}, Record<string, any>, interProjectCopyLogicMeta>;

export const interProjectCopyLogic = kea<interProjectCopyLogicType>([
    path(['scenes', 'resource-transfer', 'interProjectCopyLogic']),

    selectors({
        canCopyToProject: [
            () => [organizationLogic.selectors.currentOrganization, featureFlagLogic.selectors.featureFlags],
            (currentOrganization: null | import("../../types").OrganizationType, featureFlags: import("lib/logic/featureFlagLogic").FeatureFlagsSet): boolean => {
                const hasMultipleProjects = (currentOrganization?.teams?.length ?? 0) > 1
                const interProjectTransfersEnabled = !!featureFlags[FEATURE_FLAGS.INTER_PROJECT_TRANSFERS]
                return hasMultipleProjects && interProjectTransfersEnabled
            },
        ],
    }),
])
